import{_ as i,o as a,c as t,ag as n}from"./chunks/framework.BDReElpY.js";const m=JSON.parse('{"title":"VXM Native Module Linking Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/advanced/vxm-native-module-linking.md","filePath":"guide/advanced/vxm-native-module-linking.md"}'),o={name:"guide/advanced/vxm-native-module-linking.md"};function s(r,e,l,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="vxm-native-module-linking-architecture" tabindex="-1">VXM Native Module Linking Architecture <a class="header-anchor" href="#vxm-native-module-linking-architecture" aria-label="Permalink to &quot;VXM Native Module Linking Architecture&quot;">​</a></h1><p>Vex uses a highly optimized module caching system known as <strong>VXM (Vex Module) Native Linking</strong>. This system drastically reduces compilation times for large projects by caching dependencies as pre-compiled, fully-optimized LLVM Bitcode (<code>.bc</code>), bypassing parsing, AST generation, and High-Level IR (HIR) lowering for all upstream dependencies.</p><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>In a traditional compiler, importing a large library like <code>std/http</code> or <code>std/regex</code> forces the compiler to parse thousands of lines of code, resolve types, and generate IR for the entire library every time you compile your application. This can turn a 100ms compilation into a 5-second compilation, especially for heavily layered applications.</p><h2 id="the-vxm-solution" tabindex="-1">The VXM Solution <a class="header-anchor" href="#the-vxm-solution" aria-label="Permalink to &quot;The VXM Solution&quot;">​</a></h2><p>VXM introduces a two-phase compilation architecture:</p><ol><li><strong>Independent Package Codegen (<code>vex build</code>)</strong></li><li><strong>Transparent Consumer Linking (<code>vex compile</code> / <code>vex run</code>)</strong></li></ol><h3 id="phase-1-library-mode-compilation" tabindex="-1">Phase 1: Library Mode Compilation <a class="header-anchor" href="#phase-1-library-mode-compilation" aria-label="Permalink to &quot;Phase 1: Library Mode Compilation&quot;">​</a></h3><p>When a package defines a <code>&quot;lib&quot;</code> entry in its <code>vex.json</code> manifest, running <code>vex build</code> activates <strong>Library Mode</strong>.</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;my_library&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.0.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;lib&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/lib.vx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>During Library Mode compilation:</p><ul><li><strong>Dead Code Elimination (DCE) is Disabled</strong>: The compiler preserves all exported functions (and generic templates via sidecars) rather than aggressively stripping them. This ensures that any future consumer of the library has access to the full API.</li><li><strong>Bitcode Emission</strong>: The compiler runs its full optimization pipeline (O2/O3) and outputs a single <code>package.bc</code> LLVM Bitcode file.</li><li><strong>Global Caching</strong>: The resulting <code>.bc</code> file is cached globally in <code>~/.vex/cache/packages/&lt;name&gt;/&lt;version&gt;/package.bc</code>.</li></ul><h3 id="phase-2-transparent-consumer-linking" tabindex="-1">Phase 2: Transparent Consumer Linking <a class="header-anchor" href="#phase-2-transparent-consumer-linking" aria-label="Permalink to &quot;Phase 2: Transparent Consumer Linking&quot;">​</a></h3><p>When you build an application that imports <code>my_library</code>, the Vex Package Manager (<code>vex-pm</code>) automatically intercepts the import graph.</p><ol><li><strong>Dependency Resolution</strong>: <code>vex-pm</code> identifies that <code>my_library</code> is already built and cached.</li><li><strong>AST Bypass</strong>: The compiler completely skips parsing and type-checking the implementation of <code>my_library</code>.</li><li><strong>Link-Time Injection</strong>: Instead, <code>vex-pm</code> passes the cached <code>package.bc</code> directly to the linker (LLD or Clang fallback).</li></ol><h3 id="link-time-optimization-lto-integration" tabindex="-1">Link-Time Optimization (LTO) Integration <a class="header-anchor" href="#link-time-optimization-lto-integration" aria-label="Permalink to &quot;Link-Time Optimization (LTO) Integration&quot;">​</a></h3><p>Because Vex relies on a bundled, fixed LLVM version (v22), the cached bitcode files are perfectly compatible with the consumer&#39;s emitted bitcode.</p><p>When the linker runs, it executes <strong>Link-Time Optimization (LTO)</strong> across the consumer code and the pre-compiled VXM modules. This enables:</p><ul><li><strong>Cross-Module Inlining</strong>: A function call to <code>my_library::fast_math()</code> can be perfectly inlined into the consumer&#39;s loop, just as if it were compiled from source in the same module.</li><li><strong>Zero-Cost Abstractions</strong>: The runtime performance is completely unaffected by the compilation boundary.</li><li><strong>Late Dead-Code Elimination</strong>: While the cached <code>.bc</code> file contained <em>all</em> exported functions, the final linker (LLD) will strip out the ones your application didn&#39;t actually use, ensuring your final binary remains tiny.</li></ul><h2 id="local-workspaces-and-standard-library" tabindex="-1">Local Workspaces and Standard Library <a class="header-anchor" href="#local-workspaces-and-standard-library" aria-label="Permalink to &quot;Local Workspaces and Standard Library&quot;">​</a></h2><p>The same VXM mechanics apply to the Vex Standard Library (<code>std/*</code>). Standard library modules are pre-compiled and shipped with the toolchain as <code>.bc</code> objects. When you <code>import std::http</code>, Vex links the precompiled <code>std_http.bc</code> transparently.</p><p>Local workspace dependencies (e.g., a monorepo with multiple local libraries) also use VXM caching. The workspace resolver determines if the local library source has changed since the last <code>package.bc</code> generation, and rebuilds the bitcode cache only if necessary.</p>`,22)])])}const u=i(o,[["render",s]]);export{m as __pageData,u as default};
